// Dedup: track already-notified issue IDs + statuses using workflow static data.
// Only notify when a task is NEWLY in_review or blocked (or changes status).

const staticData = $getWorkflowStaticData('global');
if (!staticData.notifiedMap) staticData.notifiedMap = {};

const issues = $input.first()?.json ?? [];
const now = Date.now();
const newAlerts = [];

// Build current set of issue IDs for cleanup
const currentIds = new Set();

for (const issue of issues) {
  if (!issue?.id) continue;
  currentIds.add(issue.id);

  const key = issue.id;
  const prevStatus = staticData.notifiedMap[key];

  // Notify if: never seen before, or status changed
  if (!prevStatus || prevStatus !== issue.status) {
    const agentName = issue.assigneeAgentId ? (issue.executionAgentNameKey || 'agent') : 'unassigned';
    const statusEmoji = issue.status === 'blocked' ? '\uD83D\uDEAB' : '\uD83D\uDC40';

    newAlerts.push({
      id: issue.id,
      identifier: issue.identifier || 'unknown',
      title: issue.title || 'Untitled',
      status: issue.status,
      statusEmoji,
      agentName,
      priority: issue.priority || 'medium',
      updatedAt: issue.updatedAt || new Date().toISOString()
    });

    staticData.notifiedMap[key] = issue.status;
  }
}

// Clean up stale entries (issues no longer in_review/blocked)
for (const id of Object.keys(staticData.notifiedMap)) {
  if (!currentIds.has(id)) {
    delete staticData.notifiedMap[id];
  }
}

return [{ json: { hasAlerts: newAlerts.length > 0, alerts: newAlerts, totalActive: issues.length } }];

// Build Discord embed from alerts
const data = $input.first().json;
const alerts = data.alerts;

const PAPERCLIP_UI = 'http://127.0.0.1:3100';
const PREFIX = 'ROB';

const embeds = alerts.map(a => {
  const link = `${PAPERCLIP_UI}/${PREFIX}/issues/${a.identifier}`;
  const color = a.status === 'blocked' ? 0xFF0000 : 0xFFA500;
  return {
    title: `${a.statusEmoji} ${a.identifier}: ${a.title}`,
    url: link,
    color,
    fields: [
      { name: 'Status', value: `\`${a.status}\``, inline: true },
      { name: 'Agent', value: `\`${a.agentName}\``, inline: true },
      { name: 'Priority', value: `\`${a.priority}\``, inline: true }
    ],
    timestamp: a.updatedAt
  };
});

const payload = {
  content: `**Paperclip Review Alert** - ${data.totalActive} task(s) awaiting review/unblock`,
  embeds: embeds.slice(0, 10)
};

return [{ json: payload }];
